CREATE OR REPLACE FUNCTION fpa_cnv2newcon (as_oldcon text) RETURNS varchar AS $body$
DECLARE

  ls_loantype char(2);
  ls_extend varchar(100);
  li_p1 integer;
  li_p2 integer;
  ls_year char(2);
  ls_run varchar(10);
  ls_newcon char(15);

BEGIN
  -- ส001059-02/2549
  ls_loantype := substr(as_oldcon,1,2);
  if ls_loantype = 'ส0' then
    ls_loantype := 'สม';
  elsif ls_loantype = 'ฉ0' then
    ls_loantype := 'ฉฉ';
  end if;

  ls_year := substr(as_oldcon,length(as_oldcon) - 1);
  li_p1 := position('-' in as_oldcon);
  li_p2 := position('/' in as_oldcon);

  if li_p1 > 0 then
    ls_extend := substr(as_oldcon,li_p1,li_p2 - li_p1 );
    ls_run := substr(as_oldcon,3,li_p1 - 3);
  else
    ls_run := substr(as_oldcon,3,li_p2 - 3);
  end if;
  ls_run := trim(both to_char((ls_run)::numeric ,'000000'));

  ls_newcon := ls_loantype||ls_year||ls_run||ls_extend;

  return trim(both ls_newcon);
exception when others then CALL spa_dberror('');
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
